<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Logger { static function colorise(string $message, ...$code): string { return sprintf("\e[%sm%s\e[0m ", implode(';', $code), $message); } static function stringifyArray(mixed $mixed, array $expressions = [], array $placeholders = []): string { $mixed = Utilities::flatten($mixed); foreach ($mixed as $key => $value) { if ($value === true) $mixed[$key] = '✅'; elseif ($value === false) $mixed[$key] = '❌'; elseif ($value === null) $mixed[$key] = '⚠️'; elseif ($value === "") $mixed[$key] = '❓'; } return ' ' . trim(preg_replace( [ '/\s+=>\s+/', '/Array\s+\(/i', '/stdClass\s+Object\s+\(/i', '/(Enum[^\s]*)\s+\(/i', '/(\n\s*)\)/', '/ {4}/', '/\n\s*\n/', '/\[([^\]]+)\]/', ...array_keys($expressions), ], [ ' ', '', '', '$1', '', ' ', PHP_EOL, self::colorise('$1', 1, 36), ...array_values($expressions), ], self::removeSurplus(print_r(Utilities::nest($mixed), true), $placeholders) )); } static function stringifyException(\Throwable $throwable, bool $verbose = false, array $placeholders = []): string { $exception = self::removeSurplus($throwable->getMessage(), $placeholders) . "\n"; if ($verbose) $exception .= self::removeSurplus(Resources::getPathOptimised($throwable->getFile()), $placeholders) . ':' . $throwable->getLine() . "\n" . self::removeSurplus($throwable->getTraceAsString(), $placeholders) . "\n"; return $exception; } private static function removeSurplus(string $message, array $placeholders = []): string { return str_replace( [...array_keys($placeholders), TAPMEPPE_FRAMEWORK . '/', TAPMEPPE_NAMESPACE], [...array_values($placeholders), '~/', '#\\'], $message, ); } } 